using Microsoft.AspNetCore.Mvc; using ModularMonolith.BuildingBlocks.Errors; using ModularMonolith.Modules.Users.Api.Requests; using ModularMonolith.Modules.Users.Application;
namespace ModularMonolith.Modules.Users.Api.Controllers;
[ApiController,Route("api/users")] public sealed class UsersController(UsersService users):ControllerBase
{ [HttpPost] public async Task<ActionResult<UserResponse>> Create(CreateUserRequest r,CancellationToken ct)=>this.ToActionResult(await users.CreateAsync(r.FirstName,r.LastName,r.Email,ct)); [HttpGet("{id:guid}")] public async Task<ActionResult<UserResponse>> Get(Guid id,CancellationToken ct)=>this.ToActionResult(await users.GetAsync(id,ct)); [HttpPost("{id:guid}/activate")] public async Task<ActionResult<UserResponse>> Activate(Guid id,CancellationToken ct)=>this.ToActionResult(await users.SetActiveAsync(id,true,ct)); [HttpPost("{id:guid}/deactivate")] public async Task<ActionResult<UserResponse>> Deactivate(Guid id,CancellationToken ct)=>this.ToActionResult(await users.SetActiveAsync(id,false,ct)); }
